import { AttachInternals, Component, Element, EventEmitter, Host, Prop, h, Event, State, Listen, Watch, Fragment } from '@stencil/core';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { generateRandId } from '../../utils/utils';
import { CountryCodeIconNameType, CountryCodeItemSelected, CountryCodeLocation, CountryCodeValueItem } from './wdpr-country-code.model';
import { findNextEnabledIndex, getInitialFocusIndex, itemMatchesFilter } from './wdpr-country-code.utils';
import { FLAG_SVGS } from '../../utils/flags';
import { InlineMessageSize } from '../wdpr-inline-message/wdpr-inline-message.model';
import { RadialLoaderSize, RadialLabelPlacement } from '../wdpr-radial-loader/wdpr-radial-loader.model';

@Component({
  tag: 'wdpr-country-code',
  scoped: true,
  styleUrl: 'wdpr-country-code.css',
  formAssociated: true,
})
export class WdprCountryCode {
  private _listId: string = '';
  private _textFieldId: string = '';
  private _defaultSelectedId: string | null = null;
  private _slotObserver: MutationObserver;
  private _listEl: HTMLDivElement | null = null;
  private _cachedItems: HTMLWdprCountryCodeItemElement[] | null = null;
  private _measureDebounceTimer: ReturnType<typeof setTimeout>;

  @Element() el: HTMLWdprCountryCodeElement;

  @AttachInternals() internals: ElementInternals;

  @Prop() label: string = '';
  @Prop() helperText: string = '';
  @Prop() disabled: boolean = false;
  @Prop() error: boolean = false;
  @Prop({ reflect: true }) location: CountryCodeLocation = 'below';
  @Prop() showCountryCodeOnly: boolean = false;
  @Prop() required: boolean = false;
  @Prop() name?: string;
  @Prop({ reflect: true }) value: string = '';
  @Prop() noDivider: boolean = false;
  @Prop() maxViewableItems: number | null = null;

  @Prop() isLoading: boolean = false;
  @Prop() loadingText: string = 'Loading...';
  @Prop() loaderSize: RadialLoaderSize = 'medium';
  @Prop() loaderLabelPlacement: RadialLabelPlacement = 'inline';
  @Prop() showLoaderLabel: boolean = true;
  @Prop() emptyText: string = 'No results.';
  @Prop() emptyTextSize: InlineMessageSize = 'default';
  @Prop() isErrorLoading: boolean = false;
  @Prop() errorText: string = 'Failed to load items. Please try again.';
  @Prop() errorTextSize: InlineMessageSize = 'default';

  @State() _expanded = false;
  @State() _inputValue = '';
  @State() _focusedIndex: number = -1;
  @State() _activeDescendantId?: string = undefined;
  @State() _selectedValue: CountryCodeValueItem | null = null;
  @State() _readyToShow: boolean = false;
  @State() _measuredMaxHeight: string | null = null;
  @State() _flagToDisplay: string | null = null;

  @Event() wdprValueChanged: EventEmitter<string>;
  @Event() wdprSelectionChange: EventEmitter<{ selectedValue: CountryCodeValueItem | null }>;

  @Watch('value')
  handleValueChanged() {
    this._applyValue();
  }

  @Watch('_expanded')
  handleExpandedChange(newValue: boolean) {
    if (!newValue) {
      this._activeDescendantId = undefined;
      this._setFocusIndex(null);
    }
  }

  @Watch('maxViewableItems')
  handleMaxViewableItemsChange() {
    requestAnimationFrame(() => {
      this._measureItemHeights();
    });
  }

  @Watch('_inputValue')
  handleInputValueChange() {
    clearTimeout(this._measureDebounceTimer);
    this._measureDebounceTimer = setTimeout(() => {
      this._applyFilter();
      requestAnimationFrame(() => this._measureItemHeights());
    }, 100);
  }

  @Watch('_selectedValue')
  updateSelectedValue() {
    this._syncSelectionItemsState();
    this._applyFilter();
    this._updateFormValue();
    this._setSelectedFlag();
  }

  @Watch('name')
  @Watch('required')
  @Watch('disabled')
  formPropsChanged() {
    this._updateFormValue();
  }

  @Listen('wdprSelect')
  handleItemSelect(event: CustomEvent<CountryCodeItemSelected>) {
    event.stopPropagation();
    this._updateSelection(event.detail);
    this._closeDropdown();
  }

  @Listen('click', { target: 'document' })
  handleClickOutside(event: MouseEvent) {
    if (this._expanded && this.el && !event.composedPath().includes(this.el)) {
      this._closeDropdown();
    }
  }

  @Listen('resetform')
  handleResetForm() {
    this._updateFormValue();
  }

  componentWillLoad() {
    this._listId = `wdpr-country-code-list-${generateRandId()}`;
    this._textFieldId = `wdpr-country-code-input-${generateRandId()}`;
    this._updateFormValue();
  }

  componentDidLoad() {
    requestAnimationFrame(() => {
      this._invalidateItemsCache();
      this._applyValue();
      this._measureItemHeights();
      if (this._listEl) {
        this._slotObserver.observe(this._listEl, { childList: true, subtree: true });
      }
    });

    this._slotObserver = new MutationObserver(mutations => {
      const nodes = mutations.flatMap(m => Array.from(m.addedNodes)).filter((n): n is HTMLElement => n.nodeType === Node.ELEMENT_NODE);
      if (nodes.length === 0) return;

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      Promise.all(nodes.map(el => ('componentOnReady' in el ? (el as any).componentOnReady() : Promise.resolve()))).then(() => {
        this._invalidateItemsCache();
        if (this.value && !this._selectedValue) {
          this._applyValue();
        }
        this._measureItemHeights();
      });
    });
  }

  connectedCallback() {
    this.internals?.form?.addEventListener('reset', this._handleFormReset);
  }

  disconnectedCallback() {
    this.internals?.form?.removeEventListener('reset', this._handleFormReset);
    this._slotObserver?.disconnect();
  }

  private _getAllListItems(): HTMLWdprCountryCodeItemElement[] {
    if (!this._cachedItems?.length) {
      this._cachedItems = Array.from(this.el.querySelectorAll('wdpr-country-code-item'));
    }

    return this._cachedItems;
  }

  private _invalidateItemsCache() {
    this._cachedItems = null;
  }

  private _getAllVisibleItems(): HTMLWdprCountryCodeItemElement[] {
    return this._getAllListItems().filter(item => !item.isHidden);
  }

  private _applyValue(): void {
    const allItems = this._getAllListItems();

    if (!this.value) {
      this._selectedValue = null;
      this._inputValue = '';

      return;
    }

    const matchedItem = allItems.find(item => !item.disabled && (item.label === this.value || item.callingCode === this.value));

    if (matchedItem) {
      this._selectedValue = { value: matchedItem.value, label: matchedItem.label, id: matchedItem.id, isoCode: matchedItem.isoCode, callingCode: matchedItem.callingCode };
      this._setInputFromLabel(matchedItem.label, matchedItem.callingCode);
    } else {
      this._selectedValue = null;
      this._inputValue = this.value;
    }

    this._defaultSelectedId = this._selectedValue?.id ?? null;
  }

  private _applyFilter(): void {
    const items = this._getAllListItems();
    if (!items.length) return;

    const visibleItems: HTMLWdprCountryCodeItemElement[] = [];

    items.forEach(item => {
      const matches = itemMatchesFilter(item, this._inputValue);
      item.isHidden = !matches;
      if (matches) visibleItems.push(item);
    });
  }

  private _updateSelection(item: CountryCodeItemSelected): void {
    const { selected, value, label, id, isoCode, callingCode } = item;
    if (selected) {
      this._selectedValue = { value, label, id, isoCode, callingCode };
      this._setInputFromLabel(label, callingCode);
    } else {
      this._selectedValue = null;
      this._clearInput();
    }

    this.wdprSelectionChange.emit({ selectedValue: this._selectedValue });
    this.wdprValueChanged.emit(this._inputValue);
  }

  private _syncSelectionItemsState(): void {
    this._getAllListItems().forEach(item => {
      item.selected = this._selectedValue?.id === item.id;
    });
  }

  private _setInputFromLabel(label: string, code: string) {
    this._inputValue = this.showCountryCodeOnly ? code : `${code} ${label}`;
  }

  private _clearInput() {
    this._inputValue = '';
  }

  private _closeDropdown() {
    this._expanded = false;
    if (this._selectedValue) {
      this._setInputFromLabel(this._selectedValue.label, this._selectedValue.callingCode);
    }
  }

  private _updateFormValue() {
    const selectedValue = this._selectedValue?.value || '';
    const shouldSubmit = !this.disabled && !!this.name && !!selectedValue;
    this.internals?.setFormValue?.(shouldSubmit ? selectedValue : null);
    this._updateValidity();
  }

  private _updateValidity() {
    if (this.disabled || !this.required) {
      this.internals?.setValidity?.({});

      return;
    }

    if (!this._selectedValue?.value) {
      this.internals?.setValidity?.({ valueMissing: true }, 'This field is required');

      return;
    }

    this.internals?.setValidity?.({});
  }

  private _focusItemAtIndex(index: number, items: HTMLWdprCountryCodeItemElement[]): void {
    this._setFocusIndex(index);
    this._activeDescendantId = items[index]?.id ?? undefined;

    const focusedItem = items[index];
    if (focusedItem) {
      const listbox = this.el?.querySelector('.listbox');
      if (listbox) {
        focusedItem.scrollIntoView({ block: 'nearest', inline: 'nearest' });
      }
    }
  }

  private _setFocusIndex(index: number | null): void {
    this._getAllListItems().forEach((item, i) => {
      item.isFocused = i === index;
    });
    this._focusedIndex = index == null ? -1 : index;
  }

  private _measureItemHeights(): void {
    this._readyToShow = false;

    if (this.maxViewableItems == null || this.maxViewableItems <= 0) {
      this._measuredMaxHeight = null;
      this._readyToShow = true;

      return;
    }

    const visibleItems = this._getAllVisibleItems();
    const listbox = this.el?.querySelector('.listbox');

    if (!listbox || visibleItems.length === 0) {
      this._readyToShow = true;

      return;
    }

    if (visibleItems.length <= this.maxViewableItems) {
      this._measuredMaxHeight = null;
      this._readyToShow = true;

      return;
    }

    const targetItem = visibleItems[this.maxViewableItems - 1];
    const wrapperRect = listbox.getBoundingClientRect();
    const itemRect = targetItem.getBoundingClientRect();

    let calculatedHeight = Math.ceil(itemRect.bottom - wrapperRect.top);
    const style = window.getComputedStyle(listbox);
    calculatedHeight += parseFloat(style.paddingBottom) || 0;

    this._measuredMaxHeight = `${calculatedHeight}px`;
    this._readyToShow = true;
  }

  private _handleFormReset = () => {
    if (this._defaultSelectedId) {
      const defaultItem = this._getAllListItems().find(i => i.id === this._defaultSelectedId);
      if (defaultItem) {
        this._selectedValue = { value: defaultItem.value, label: defaultItem.label, id: defaultItem.id, isoCode: defaultItem.isoCode, callingCode: defaultItem.callingCode };
        this._setInputFromLabel(defaultItem.label, defaultItem.callingCode);
        this._updateFormValue();

        return;
      }
    }

    this._selectedValue = null;
    this._clearInput();
    this._updateFormValue();
  };

  private _handleKeydown = (ev: KeyboardEvent): void => {
    if (this.disabled) return;

    const items = this._getAllListItems();
    if (!items.length) return;

    if (ev.key === KEYBOARD_KEYS.ENTER || (ev.key === KEYBOARD_KEYS.SPACE && this._focusedIndex >= 0)) {
      ev.preventDefault();
      if (!this._expanded) {
        this._expanded = true;
        const startIndex = getInitialFocusIndex(items, 'down');
        this._focusItemAtIndex(startIndex, items);
      } else {
        const focusedItem = items[this._focusedIndex];
        if (focusedItem && !focusedItem.disabled) {
          focusedItem.click();
        }
      }

      return;
    }

    if (ev.key === KEYBOARD_KEYS.ARROW_DOWN) {
      ev.preventDefault();
      if (!this._expanded) {
        this._expanded = true;
        this._focusItemAtIndex(getInitialFocusIndex(items, 'down'), items);

        return;
      }
      this._focusItemAtIndex(findNextEnabledIndex(items, this._focusedIndex, 'down'), items);
    }

    if (ev.key === KEYBOARD_KEYS.ARROW_UP) {
      ev.preventDefault();
      if (!this._expanded) {
        this._expanded = true;
        this._focusItemAtIndex(getInitialFocusIndex(items, 'up'), items);

        return;
      }
      this._focusItemAtIndex(findNextEnabledIndex(items, this._focusedIndex, 'up'), items);
    }

    if (ev.key === KEYBOARD_KEYS.ESCAPE || ev.key === KEYBOARD_KEYS.TAB) {
      this._closeDropdown();
    }
  };

  private _handleInput = (event: Event) => {
    event.stopPropagation();
    const value = (event.target as HTMLInputElement).value;
    this._inputValue = value;

    if (this._selectedValue) {
      this._selectedValue = null;
      this.wdprSelectionChange.emit({ selectedValue: null });
      this._updateFormValue();
    }

    if (!this._expanded) this._expanded = true;
    this.wdprValueChanged.emit(value);
  };

  private _handleWrapperClick = () => {
    if (this.disabled) return;
    if (!this._expanded) this._expanded = true;
  };

  private _handleArrowClick = (e: MouseEvent) => {
    e.stopPropagation();
    e.preventDefault();
    if (this.disabled) return;
    this._expanded = !this._expanded;
  };

  private _setSelectedFlag(): void {
    if (!this._selectedValue) {
      this._flagToDisplay = null;

      return;
    }

    const item = this._getAllListItems().find(i => i.id === this._selectedValue.id);
    const isWindows = typeof window !== 'undefined' && navigator.userAgent.includes('Windows');

    if (item && item.isoCode) {
      if (isWindows && FLAG_SVGS[item.isoCode]) {
        this._flagToDisplay = FLAG_SVGS[item.isoCode];
      } else {
        this._flagToDisplay = this._countryCodeToFlag(item.isoCode);
      }
    }
  }

  private _countryCodeToFlag(isoCode: string): string {
    if (!isoCode || isoCode.length !== 2) return '';
    const codePoints = isoCode
      .toUpperCase()
      .split('')
      .map(char => 0x1f1e6 + char.charCodeAt(0) - 65);

    return String.fromCodePoint(...codePoints);
  }

  private _renderFlagDisplay() {
    if (!this._flagToDisplay) {
      return (
        <span class="country-code-empty-flag" aria-hidden="true">
          --
        </span>
      );
    }

    if (this._flagToDisplay.startsWith('<svg')) {
      return <span class="country-code-flag-svg" aria-hidden="true" innerHTML={this._flagToDisplay} />;
    }

    return (
      <span class="country-code-flag" aria-hidden="true">
        {this._flagToDisplay}
      </span>
    );
  }

  private _renderCombobox() {
    return (
      <Fragment>
        <div class="country-code-wrapper">
          <div class="country-code-container">
            <div class="country-code-flag-wrapper">{this._renderFlagDisplay()}</div>

            <div class="country-code-divider">
              <wdpr-divider orientation="vertical"></wdpr-divider>
            </div>

            <div class="country-code-input-wrapper">
              <input
                id={this._textFieldId}
                type="text"
                class="input"
                value={this._inputValue}
                placeholder={this.label}
                disabled={this.disabled}
                onClick={this._handleWrapperClick}
                onInput={this._handleInput}
                onKeyDown={this._handleKeydown}
                autocomplete="off"
                role="combobox"
                aria-autocomplete="list"
                aria-expanded={this._expanded.toString()}
                aria-invalid={this.error.toString()}
                aria-controls={this._listId}
                aria-haspopup="listbox"
                aria-activedescendant={this._activeDescendantId || undefined}
                aria-required={this.required.toString()}
                aria-describedby={this.helperText ? `${this._textFieldId}-helper-text` : undefined}
                aria-label={this.label}
              />
            </div>

            <div class="icon-wrapper">
              <wdpr-icon-button iconName={this._getIconName()} disabled={this.disabled} a11yLabel={this._getIconButtonAriaLabel()} onClick={this._handleArrowClick} />
            </div>
          </div>
        </div>

        {this._renderInlineMessage()}
      </Fragment>
    );
  }

  private _renderInlineMessage(): JSX.Element {
    return (
      this.helperText && (
        <div class="inline-message-wrapper">
          <wdpr-inline-message id={`${this._textFieldId}-helper-text`} variant={this.error ? 'error' : 'informational'} size="small" role="status">{this.helperText}</wdpr-inline-message>
        </div>
      )
    );
  }

  private _renderList() {
    return (
      <div ref={el => (this._listEl = el)} class="listbox" role="listbox" id={this._listId} aria-label={this.label}>
        <slot />
      </div>
    );
  }

  private _renderListWrapper() {
    const visibilityClass = this._isListVisible ? 'country-code-list-container-visible' : 'country-code-list-container-invisible';

    return (
      <div class={`country-code-list-container ${visibilityClass}`} style={{ height: this._measuredMaxHeight }}>
        {this._renderList()}
      </div>
    );
  }

  private _renderStatusMessage(): JSX.Element | null {
    const isEmpty = this._getAllListItems().length === 0;

    if (!this._expanded) return null;
    if (this.isLoading)
      return (
        <div class="loading-container" role="status" aria-live="polite" aria-atomic="true">
          <wdpr-radial-loader size={this.loaderSize} label={this.loadingText} labelPlacement={this.loaderLabelPlacement} showLabel={this.showLoaderLabel} />
        </div>
      );
    if (isEmpty && !this.isErrorLoading && !this.isLoading)
      return (
        <div class="empty-container">
          <wdpr-inline-message variant="informational" size={this.emptyTextSize} role="status" a11yLive="polite">{this.emptyText}</wdpr-inline-message>
        </div>
      );
    if (this.isErrorLoading && !this.isLoading)
      return (
        <div class="error-container">
          <wdpr-inline-message variant="error" size={this.errorTextSize} role="status" a11yLive="polite">{this.errorText}</wdpr-inline-message>
        </div>
      );

    return null;
  }

  private _getIconName(): CountryCodeIconNameType {
    return this._expanded ? 'expand-show-less' : 'expand-show-more';
  }

  private _getIconButtonAriaLabel(): string {
    const closedLabel = 'Open list';
    const openLabel = 'Close list';

    return this._expanded ? openLabel : closedLabel;
  }

  private get _isListVisible(): boolean {
    return this._readyToShow && this._expanded && !this.isLoading && this._getAllListItems().length > 0 && !this.isErrorLoading;
  }

  render() {
    return (
      <Host>
        {this._renderCombobox()}
        {this._renderListWrapper()}
        {this._renderStatusMessage()}
      </Host>
    );
  }
}
